import React from "react";
import "./Sidebar.css";

const Sidebar = ({ 
  isOpen, 
  setIsOpen, 
  view, 
  setView, 
  groups, 
  peers, 
  selectedGroup, 
  selectGroup 
}) => {
  return (
    <aside className={`sidebar ${isOpen ? "open" : ""}`}>
      <div className="sidebar-section">
        <h3 className="sidebar-title">NAVIGATION</h3>

        <button
          className={`sidebar-link ${view === "dashboard" ? "active" : ""}`}
          onClick={() => { setView("dashboard"); setIsOpen(false); }}
        >
          <span className="sidebar-icon">📊</span>
          <span className="sidebar-label">Dashboard</span>
        </button>

        <button
          className={`sidebar-link ${view === "groups" || view === "creategroup" || view === "joingroup" ? "active" : ""}`}
          onClick={() => { setView("groups"); setIsOpen(false); }}
        >
          <span className="sidebar-icon">👥</span>
          <span className="sidebar-label">Groups</span>
          <span className="count-badge">{groups?.length || 0}</span>
        </button>

        <button
          className={`sidebar-link ${view === "peers" ? "active" : ""}`}
          onClick={() => { setView("peers"); setIsOpen(false); }}
        >
          <span className="sidebar-icon">💻</span>
          <span className="sidebar-label">Peers</span>
          <span className="count-badge">{peers?.length || 0}</span>
        </button>
      </div>

      <div className="sidebar-section">
        <h3 className="sidebar-title">NETWORK SHARING</h3>

        <button 
          className={`sidebar-link network-share-btn ${selectedGroup?.name === "__NETWORK_SHARE__" && view === "files" ? "active" : ""}`}
          onClick={() => {
            const networkGroup = groups?.find(g => g.name === "__NETWORK_SHARE__" || g.inviteCode === "NETWORK");
            if (networkGroup) {
              selectGroup(networkGroup);
            }
            setIsOpen(false);
          }}
        >
          <span className="sidebar-icon">🌐</span>
          <span className="sidebar-label">Network Share</span>
        </button>
      </div>

      {selectedGroup && selectedGroup.name !== "__NETWORK_SHARE__" && (
        <div className="sidebar-section">
          <h3 className="sidebar-title">CURRENT GROUP</h3>

          <button
            className={`sidebar-link ${view === "files" ? "active" : ""}`}
            onClick={() => { setView("files"); setIsOpen(false); }}
          >
            <span className="sidebar-icon">📁</span>
            <span className="sidebar-label truncate">{selectedGroup.name}</span>
          </button>
        </div>
      )}
    </aside>
  );
};

export default Sidebar;
